     1→// ============================================================================
     2→// FreeLang Standard Library - types.fl
     3→// ============================================================================
     4→//
     5→// 타입 변환 및 타입 검사 함수 (6개)
     6→// Phase B mod.fl의 FlValue 타입과 함께 사용
     7→//
     8→// 작성일: 2026-03-02
     9→// 단계: Phase C.1 (Week 1)
    10→
    11→use crate::stdlib::FlValue;
    12→
    13→// ============================================================================
    14→// TypeError - 타입 변환 에러 타입
    15→// ============================================================================
    16→
    17→/// 타입 변환 시 발생할 수 있는 에러
    18→#[derive(Clone, Debug, PartialEq)]
    19→pub enum TypeError {
    20→    /// 문자열 파싱 실패
    21→    ParseError(String),
    22→
    23→    /// 지원되지 않는 타입 변환
    24→    UnsupportedConversion { from: String, to: String },
    25→}
    26→
    27→impl std::fmt::Display for TypeError {
    28→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    29→        match self {
    30→            TypeError::ParseError(s) => write!(f, "ParseError: {}", s),
    31→            TypeError::UnsupportedConversion { from, to } => {
    32→                write!(f, "Cannot convert {} to {}", from, to)
    33→            }
    34→        }
    35→    }
    36→}
    37→
    38→// ============================================================================
    39→// Type Conversion Functions
    40→// ============================================================================
    41→
    42→/// 값을 정수로 변환합니다.
    43→///
    44→/// # 규칙
    45→/// - Int: 그대로 반환
    46→/// - Float: 소수점 버림
    47→/// - String: 파싱 시도 (실패 시 에러)
    48→/// - Bool: true → 1, false → 0
    49→/// - Null: 0
    50→/// - Array/Object: 에러
    51→///
    52→/// # 예제
    53→/// ```
    54→/// assert_eq!(to_int(FlValue::Int(42)), Ok(42));
    55→/// assert_eq!(to_int(FlValue::Float(3.7)), Ok(3));
    56→/// assert_eq!(to_int(FlValue::Bool(true)), Ok(1));
    57→/// assert_eq!(to_int(FlValue::Str("42".to_string())), Ok(42));
    58→/// ```
    59→pub fn to_int(value: FlValue) -> Result<i64, TypeError> {
    60→    match value {
    61→        FlValue::Int(n) => Ok(n),
    62→        FlValue::Float(f) => Ok(f as i64),
    63→        FlValue::Str(s) => s.trim()
    64→            .parse::<i64>()
    65→            .map_err(|_| TypeError::ParseError(s)),
    66→        FlValue::Bool(b) => Ok(if b { 1 } else { 0 }),
    67→        FlValue::Null => Ok(0),
    68→        other => Err(TypeError::UnsupportedConversion {
    69→            from: other.type_name().to_string(),
    70→            to: "int".to_string(),
    71→        }),
    72→    }
    73→}
    74→
    75→/// 값을 부동소수점으로 변환합니다.
    76→///
    77→/// # 규칙
    78→/// - Float: 그대로 반환
    79→/// - Int: 정수로 변환
    80→/// - String: 파싱 시도
    81→/// - Bool: true → 1.0, false → 0.0
    82→/// - Null: 0.0
    83→/// - Array/Object: 에러
    84→///
    85→/// # 예제
    86→/// ```
    87→/// assert_eq!(to_float(FlValue::Float(3.14)), Ok(3.14));
    88→/// assert_eq!(to_float(FlValue::Int(42)), Ok(42.0));
    89→/// ```
    90→pub fn to_float(value: FlValue) -> Result<f64, TypeError> {
    91→    match value {
    92→        FlValue::Float(f) => Ok(f),
    93→        FlValue::Int(n) => Ok(n as f64),
    94→        FlValue::Str(s) => s.trim()
    95→            .parse::<f64>()
    96→            .map_err(|_| TypeError::ParseError(s)),
    97→        FlValue::Bool(b) => Ok(if b { 1.0 } else { 0.0 }),
    98→        FlValue::Null => Ok(0.0),
    99→        other => Err(TypeError::UnsupportedConversion {
   100→            from: other.type_name().to_string(),
   101→            to: "float".to_string(),
   102→        }),
   103→    }
   104→}
   105→
   106→/// 값을 문자열로 변환합니다.
   107→///
   108→/// # 규칙
   109→/// - Str: 그대로 반환
   110→/// - Int/Float/Bool: 문자열로 변환
   111→/// - Null: "null" 반환
   112→/// - Array: "[array]" 반환
   113→/// - Object: "[object]" 반환
   114→///
   115→/// # 예제
   116→/// ```
   117→/// assert_eq!(to_string(FlValue::Int(42)), "42");
   118→/// assert_eq!(to_string(FlValue::Bool(true)), "true");
   119→/// assert_eq!(to_string(FlValue::Null), "null");
   120→/// ```
   121→pub fn to_string(value: FlValue) -> String {
   122→    value.to_string_repr()
   123→}
   124→
   125→/// 값을 불리언으로 변환합니다 (Truthy evaluation).
   126→///
   127→/// # 규칙 (Falsy 값)
   128→/// - Null: false
   129→/// - Bool(false): false
   130→/// - Int(0): false
   131→/// - Float(0.0): false
   132→/// - Str(""): false (빈 문자열)
   133→/// - Array([]): false (빈 배열)
   134→/// - Object({}): false (빈 객체)
   135→///
   136→/// # 나머지는 모두 true
   137→///
   138→/// # 예제
   139→/// ```
   140→/// assert_eq!(to_bool(FlValue::Int(0)), false);
   141→/// assert_eq!(to_bool(FlValue::Int(1)), true);
   142→/// assert_eq!(to_bool(FlValue::Str("hello".to_string())), true);
   143→/// assert_eq!(to_bool(FlValue::Str("".to_string())), false);
   144→/// ```
   145→pub fn to_bool(value: FlValue) -> bool {
   146→    value.is_truthy()
   147→}
   148→
   149→/// 값의 타입명을 문자열로 반환합니다.
   150→///
   151→/// # 반환값
   152→/// - Int: "int"
   153→/// - Float: "float"
   154→/// - Bool: "bool"
   155→/// - String: "string"
   156→/// - Array: "array"
   157→/// - Object: "object"
   158→/// - Null: "null"
   159→///
   160→/// # 예제
   161→/// ```
   162→/// assert_eq!(type_of(FlValue::Int(42)), "int");
   163→/// assert_eq!(type_of(FlValue::Null), "null");
   164→/// ```
   165→pub fn type_of(value: FlValue) -> &'static str {
   166→    value.type_name()
   167→}
   168→
   169→/// 값이 null인지 확인합니다.
   170→///
   171→/// # 예제
   172→/// ```
   173→/// assert_eq!(is_null(FlValue::Null), true);
   174→/// assert_eq!(is_null(FlValue::Int(0)), false);
   175→/// ```
   176→pub fn is_null(value: FlValue) -> bool {
   177→    value.is_null()
   178→}
