   226→
   227→    #[test]
   228→    fn test_to_int_from_array_error() {
   229→        let result = to_int(FlValue::Array(vec![]));
   230→        assert!(matches!(result, Err(TypeError::UnsupportedConversion { .. })));
   231→    }
   232→
   233→    // to_float 테스트
   234→    #[test]
   235→    fn test_to_float_from_float() {
   236→        assert_eq!(to_float(FlValue::Float(3.14)), Ok(3.14));
   237→        assert_eq!(to_float(FlValue::Float(0.0)), Ok(0.0));
   238→    }
   239→
   240→    #[test]
   241→    fn test_to_float_from_int() {
   242→        assert_eq!(to_float(FlValue::Int(42)), Ok(42.0));
   243→        assert_eq!(to_float(FlValue::Int(0)), Ok(0.0));
   244→    }
   245→
   246→    #[test]
   247→    fn test_to_float_from_bool() {
   248→        assert_eq!(to_float(FlValue::Bool(true)), Ok(1.0));
   249→        assert_eq!(to_float(FlValue::Bool(false)), Ok(0.0));
   250→    }
   251→
   252→    #[test]
   253→    fn test_to_float_from_string() {
   254→        assert_eq!(to_float(FlValue::Str("3.14".to_string())), Ok(3.14));
   255→        assert_eq!(to_float(FlValue::Str("-2.5".to_string())), Ok(-2.5));
   256→    }
   257→
   258→    #[test]
   259→    fn test_to_float_from_null() {
   260→        assert_eq!(to_float(FlValue::Null), Ok(0.0));
   261→    }
   262→
   263→    // to_string 테스트
   264→    #[test]
   265→    fn test_to_string_from_string() {
   266→        assert_eq!(to_string(FlValue::Str("hello".to_string())), "hello");
   267→    }
   268→
   269→    #[test]
   270→    fn test_to_string_from_int() {
   271→        assert_eq!(to_string(FlValue::Int(42)), "42");
   272→        assert_eq!(to_string(FlValue::Int(-100)), "-100");
   273→    }
   274→
   275→    #[test]
   276→    fn test_to_string_from_float() {
   277→        assert_eq!(to_string(FlValue::Float(3.14)), "3.14");
   278→    }
   279→
   280→    #[test]
   281→    fn test_to_string_from_bool() {
   282→        assert_eq!(to_string(FlValue::Bool(true)), "true");
   283→        assert_eq!(to_string(FlValue::Bool(false)), "false");
   284→    }
   285→
   286→    #[test]
   287→    fn test_to_string_from_null() {
   288→        assert_eq!(to_string(FlValue::Null), "null");
   289→    }
   290→
   291→    // to_bool 테스트 (Truthy evaluation)
   292→    #[test]
   293→    fn test_to_bool_falsy() {
   294→        assert_eq!(to_bool(FlValue::Null), false);
   295→        assert_eq!(to_bool(FlValue::Bool(false)), false);
   296→        assert_eq!(to_bool(FlValue::Int(0)), false);
   297→        assert_eq!(to_bool(FlValue::Float(0.0)), false);
   298→        assert_eq!(to_bool(FlValue::Str("".to_string())), false);
   299→        assert_eq!(to_bool(FlValue::Array(vec![])), false);
   300→    }
   301→
   302→    #[test]
   303→    fn test_to_bool_truthy() {
   304→        assert_eq!(to_bool(FlValue::Bool(true)), true);
   305→        assert_eq!(to_bool(FlValue::Int(1)), true);
   306→        assert_eq!(to_bool(FlValue::Int(-1)), true);
   307→        assert_eq!(to_bool(FlValue::Float(1.0)), true);
   308→        assert_eq!(to_bool(FlValue::Str("hello".to_string())), true);
