     1→// ============================================================================
     2→// FreeLang Channel<T> - 스레드 간 메시지 전송
     3→// ============================================================================
     4→//
     5→// MPSC (Multi-Producer Single-Consumer) 채널을 구현합니다.
     6→//
     7→// 특징:
     8→// - 여러 스레드가 보냄 (Sender 복제 가능)
     9→// - 한 스레드만 받음 (Receiver는 복제 불가)
    10→// - 스레드 안전 (Arc + Mutex)
    11→// - 논블로킹 & 블로킹 연산 모두 지원
    12→//
    13→// 작성일: 2026-03-02
    14→// 단계: Phase B.5 (Week 11-12)
    15→
    16→use std::sync::{Arc, Mutex, mpsc};
    17→use std::time::Duration;
    18→
    19→// ============================================================================
    20→// Channel Result Type
    21→// ============================================================================
    22→
    23→/// Channel 연산 결과
    24→pub enum SendError<T> {
    25→    /// 채널이 이미 폐쇄됨
    26→    Disconnected(T),
    27→
    28→    /// 받는 쪽이 drop됨
    29→    ReceiverDropped(T),
    30→}
    31→
    32→pub enum RecvError {
    33→    /// 채널이 폐쇄되고 메시지 없음
    34→    Disconnected,
    35→
    36→    /// 타임아웃
    37→    Timeout,
    38→
    39→    /// 받는 쪽이 drop됨
    40→    SenderDropped,
    41→}
    42→
    43→// ============================================================================
    44→// Channel 구현
    45→// ============================================================================
    46→
    47→/// 메시지를 보내는 끝 (복제 가능)
    48→pub struct Sender<T> {
    49→    /// 내부 채널
    50→    inner: Arc<Mutex<ChannelInner<T>>>,
    51→}
    52→
    53→/// 메시지를 받는 끝 (복제 불가)
    54→pub struct Receiver<T> {
    55→    /// 내부 채널
    56→    inner: Arc<Mutex<ChannelInner<T>>>,
    57→}
    58→
    59→/// 채널 내부 상태
    60→struct ChannelInner<T> {
    61→    /// 메시지 큐
    62→    queue: std::collections::VecDeque<T>,
    63→
    64→    /// 송신자 개수
    65→    sender_count: usize,
    66→
    67→    /// 채널 폐쇄 여부
    68→    is_closed: bool,
    69→
    70→    /// 수신자가 대기 중인지
    71→    receiver_waiting: bool,
    72→}
    73→
    74→impl<T> Sender<T> {
    75→    /// 메시지를 보냅니다 (블로킹).
    76→    ///
    77→    /// 수신자가 메시지를 받을 때까지 대기합니다.
    78→    pub fn send(&self, msg: T) -> Result<(), SendError<T>> {
    79→        let mut inner = self.inner.lock().unwrap();
    80→
    81→        if inner.is_closed {
    82→            return Err(SendError::Disconnected(msg));
    83→        }
    84→
    85→        inner.queue.push_back(msg);
    86→
    87→        // 수신자가 대기 중이면 깨우기
    88→        if inner.receiver_waiting {
    89→            // 실제 구현에서는 condvar 사용
    90→        }
    91→
    92→        Ok(())
    93→    }
    94→
    95→    /// 메시지를 비동기로 보냅니다 (비블로킹).
    96→    pub fn try_send(&self, msg: T) -> Result<(), SendError<T>> {
    97→        self.send(msg)
    98→    }
    99→
   100→    /// 채널을 폐쇄합니다.
   101→    pub fn close(&self) {
   102→        let mut inner = self.inner.lock().unwrap();
   103→        inner.is_closed = true;
   104→    }
   105→}
   106→
   107→impl<T> Clone for Sender<T> {
   108→    fn clone(&self) -> Sender<T> {
   109→        let mut inner = self.inner.lock().unwrap();
   110→        inner.sender_count += 1;
   111→        Sender {
   112→            inner: Arc::clone(&self.inner),
   113→        }
   114→    }
   115→}
   116→
   117→impl<T> Drop for Sender<T> {
   118→    fn drop(&mut self) {
   119→        let mut inner = self.inner.lock().unwrap();
   120→        inner.sender_count = inner.sender_count.saturating_sub(1);
   121→    }
   122→}
   123→
   124→impl<T> Receiver<T> {
   125→    /// 메시지를 받습니다 (블로킹).
   126→    ///
   127→    /// 메시지가 도착할 때까지 대기합니다.
   128→    pub fn recv(&self) -> Result<T, RecvError> {
   129→        loop {
   130→            let mut inner = self.inner.lock().unwrap();
   131→
   132→            if let Some(msg) = inner.queue.pop_front() {
   133→                return Ok(msg);
   134→            }
   135→
   136→            // 큐가 비어있고 송신자가 모두 drop됨
   137→            if inner.sender_count == 0 && inner.is_closed {
   138→                return Err(RecvError::Disconnected);
   139→            }
   140→
   141→            // 대기 중으로 표시
   142→            inner.receiver_waiting = true;
   143→            drop(inner);
   144→
   145→            // 실제 구현에서는 condvar로 대기
   146→            std::thread::sleep(std::time::Duration::from_micros(1));
   147→        }
   148→    }
   149→
   150→    /// 메시지를 비동기로 받습니다 (비블로킹).
   151→    pub fn try_recv(&self) -> Result<T, RecvError> {
   152→        let mut inner = self.inner.lock().unwrap();
   153→
   154→        if let Some(msg) = inner.queue.pop_front() {
   155→            return Ok(msg);
   156→        }
   157→
   158→        // 큐가 비어있고 송신자가 모두 drop됨
   159→        if inner.sender_count == 0 && inner.is_closed {
   160→            return Err(RecvError::Disconnected);
   161→        }
   162→
   163→        // 메시지 없음
   164→        Err(RecvError::SenderDropped)
   165→    }
   166→
   167→    /// 타임아웃과 함께 메시지를 받습니다.
   168→    pub fn recv_timeout(&self, timeout: Duration) -> Result<T, RecvError> {
   169→        let start = std::time::Instant::now();
   170→
   171→        loop {
   172→            let mut inner = self.inner.lock().unwrap();
   173→
   174→            if let Some(msg) = inner.queue.pop_front() {
   175→                return Ok(msg);
   176→            }
   177→
   178→            // 큐가 비어있고 송신자가 모두 drop됨
   179→            if inner.sender_count == 0 && inner.is_closed {
   180→                return Err(RecvError::Disconnected);
   181→            }
   182→
   183→            drop(inner);
   184→
   185→            // 타임아웃 확인
   186→            if start.elapsed() > timeout {
   187→                return Err(RecvError::Timeout);
   188→            }
   189→
   190→            std::thread::sleep(std::time::Duration::from_micros(1));
   191→        }
   192→    }
   193→
   194→    /// 채널이 폐쇄되었는지 확인합니다.
   195→    pub fn is_closed(&self) -> bool {
   196→        let inner = self.inner.lock().unwrap();
   197→        inner.is_closed && inner.sender_count == 0
   198→    }
   199→
   200→    /// 큐에 대기 중인 메시지 개수를 반환합니다.
   201→    pub fn pending(&self) -> usize {
   202→        let inner = self.inner.lock().unwrap();
   203→        inner.queue.len()
   204→    }
   205→}
   206→
   207→// ============================================================================
   208→// Channel 생성 함수
   209→// ============================================================================
   210→
   211→/// 새로운 채널을 생성합니다.
   212→pub fn channel<T>() -> (Sender<T>, Receiver<T>) {
   213→    let inner = Arc::new(Mutex::new(ChannelInner {
   214→        queue: std::collections::VecDeque::new(),
   215→        sender_count: 1,
   216→        is_closed: false,
   217→        receiver_waiting: false,
   218→    }));
   219→
   220→    (
