     4→//
     5→// 여러 스레드가 안전하게 공유하는 원자적 데이터 타입을 제공합니다.
     6→//
     7→// 특징:
     8→// - 모든 연산이 원자적 (분할 불가능)
     9→// - 메모리 순서 지정 가능
    10→// - 데이터 경합(data race) 불가능
    11→// - Lock-free 구현 (일반적으로)
    12→//
    13→// 작성일: 2026-03-02
    14→// 단계: Phase B.2 (Week 3-4)
    15→
    16→use crate::sync::ordering::Ordering;
    17→use std::sync::atomic::{AtomicUsize, AtomicBool, AtomicPtr};
    18→use std::sync::atomic::Ordering as StdOrdering;
    19→
    20→// ============================================================================
    21→// AtomicUsize - 원자적 부호 없는 정수
    22→// ============================================================================
    23→
    24→/// AtomicUsize: 원자적으로 접근 가능한 usize 값
    25→///
    26→/// 여러 스레드에서 동시에 접근해도 안전합니다.
    27→pub struct AtomicUsize {
    28→    // 내부 구현: Rust의 std::sync::atomic::AtomicUsize 사용
    29→    // (실제 구현에서는 LLVM IR의 atomic operation 사용)
    30→    inner: AtomicUsize,
    31→}
    32→
    33→impl AtomicUsize {
    34→    /// 새로운 AtomicUsize를 생성합니다.
    35→    ///
    36→    /// # 예제
    37→    /// ```
    38→    /// let counter = AtomicUsize::new(0);
    39→    /// ```
    40→    pub fn new(value: usize) -> AtomicUsize {
    41→        AtomicUsize {
    42→            inner: AtomicUsize::new(value),
    43→        }
    44→    }
    45→
    46→    /// 현재 값을 읽습니다.
    47→    ///
    48→    /// 지정된 메모리 순서를 준수합니다.
    49→    ///
    50→    /// # 예제
    51→    /// ```
    52→    /// let counter = AtomicUsize::new(42);
    53→    /// assert_eq!(counter.load(Ordering::SeqCst), 42);
    54→    /// ```
    55→    pub fn load(&self, order: Ordering) -> usize {
    56→        let std_order = convert_ordering(order);
    57→        self.inner.load(std_order)
    58→    }
    59→
    60→    /// 값을 쓰고 반환하지 않습니다.
    61→    ///
    62→    /// 지정된 메모리 순서를 준수합니다.
    63→    ///
    64→    /// # 예제
    65→    /// ```
    66→    /// let counter = AtomicUsize::new(0);
    67→    /// counter.store(42, Ordering::SeqCst);
    68→    /// assert_eq!(counter.load(Ordering::SeqCst), 42);
    69→    /// ```
    70→    pub fn store(&self, value: usize, order: Ordering) {
    71→        let std_order = convert_ordering(order);
    72→        self.inner.store(value, std_order)
    73→    }
    74→
    75→    /// 값을 더하고 이전 값을 반환합니다.
    76→    ///
    77→    /// # 예제
    78→    /// ```
    79→    /// let counter = AtomicUsize::new(0);
    80→    /// let old = counter.fetch_add(1, Ordering::SeqCst);
    81→    /// assert_eq!(old, 0);
    82→    /// assert_eq!(counter.load(Ordering::SeqCst), 1);
    83→    /// ```
    84→    pub fn fetch_add(&self, delta: usize, order: Ordering) -> usize {
    85→        let std_order = convert_ordering(order);
    86→        self.inner.fetch_add(delta, std_order)
    87→    }
    88→
    89→    /// 값을 빼고 이전 값을 반환합니다.
    90→    ///
    91→    /// # 예제
    92→    /// ```
    93→    /// let counter = AtomicUsize::new(10);
    94→    /// let old = counter.fetch_sub(1, Ordering::SeqCst);
    95→    /// assert_eq!(old, 10);
    96→    /// assert_eq!(counter.load(Ordering::SeqCst), 9);
    97→    /// ```
    98→    pub fn fetch_sub(&self, delta: usize, order: Ordering) -> usize {
    99→        let std_order = convert_ordering(order);
   100→        self.inner.fetch_sub(delta, std_order)
   101→    }
   102→
   103→    /// Compare-and-swap: 값이 expected이면 new로 바꾸고, 이전 값을 반환합니다.
   104→    ///
   105→    /// 이 연산은 lock-free 업데이트의 기초입니다.
   106→    ///
   107→    /// # 예제
   108→    /// ```
   109→    /// let counter = AtomicUsize::new(0);
   110→    ///
   111→    /// // 성공
   112→    /// let old = counter.compare_and_swap(0, 1, Ordering::SeqCst);
   113→    /// assert_eq!(old, 0);
   114→    /// assert_eq!(counter.load(Ordering::SeqCst), 1);
   115→    ///
   116→    /// // 실패
   117→    /// let old = counter.compare_and_swap(0, 2, Ordering::SeqCst);
   118→    /// assert_eq!(old, 1);  // 변경 안 됨
   119→    /// assert_eq!(counter.load(Ordering::SeqCst), 1);
   120→    /// ```
   121→    pub fn compare_and_swap(&self, expected: usize, new: usize, order: Ordering) -> usize {
   122→        let std_order = convert_ordering(order);
   123→        self.inner.compare_and_swap(expected, new, std_order)
   124→    }
   125→
   126→    /// 원자적으로 값을 읽고 수정합니다.
   127→    ///
   128→    /// # 예제
   129→    /// ```
   130→    /// let counter = AtomicUsize::new(5);
   131→    /// counter.fetch_update(Ordering::SeqCst, |x| Some(x * 2));
   132→    /// assert_eq!(counter.load(Ordering::SeqCst), 10);
   133→    /// ```
   134→    pub fn fetch_update<F>(&self, order: Ordering, f: F) -> Result<usize, usize>
   135→    where
   136→        F: Fn(usize) -> Option<usize>,
   137→    {
   138→        let std_order = convert_ordering(order);
   139→        self.inner.compare_exchange_weak(
   140→            self.load(order),
   141→            {
   142→                let current = self.load(order);
   143→                f(current).unwrap_or(current)
   144→            },
   145→            std_order,
   146→            std_order,
   147→        )
   148→    }
   149→}
