   152→// AtomicBool - 원자적 불린 값
   153→// ============================================================================
   154→
   155→/// AtomicBool: 원자적으로 접근 가능한 bool 값
   156→pub struct AtomicBool {
   157→    // 내부 구현: Rust의 std::sync::atomic::AtomicBool 사용
   158→    inner: AtomicBool,
   159→}
   160→
   161→impl AtomicBool {
   162→    /// 새로운 AtomicBool을 생성합니다.
   163→    pub fn new(value: bool) -> AtomicBool {
   164→        AtomicBool {
   165→            inner: AtomicBool::new(value),
   166→        }
   167→    }
   168→
   169→    /// 현재 값을 읽습니다.
   170→    pub fn load(&self, order: Ordering) -> bool {
   171→        let std_order = convert_ordering(order);
   172→        self.inner.load(std_order)
   173→    }
   174→
   175→    /// 값을 씁니다.
   176→    pub fn store(&self, value: bool, order: Ordering) {
   177→        let std_order = convert_ordering(order);
   178→        self.inner.store(value, std_order)
   179→    }
   180→
   181→    /// 값을 반전시키고 이전 값을 반환합니다.
   182→    ///
   183→    /// # 예제
   184→    /// ```
   185→    /// let flag = AtomicBool::new(false);
   186→    /// assert_eq!(flag.fetch_not(Ordering::SeqCst), false);
   187→    /// assert_eq!(flag.load(Ordering::SeqCst), true);
   188→    /// ```
   189→    pub fn fetch_not(&self, order: Ordering) -> bool {
   190→        let std_order = convert_ordering(order);
   191→        self.inner.fetch_nand(true, std_order)
   192→    }
   193→
   194→    /// Compare-and-swap: 값이 expected이면 new로 바꿉니다.
   195→    pub fn compare_and_swap(&self, expected: bool, new: bool, order: Ordering) -> bool {
   196→        let std_order = convert_ordering(order);
   197→        self.inner.compare_and_swap(expected, new, std_order)
   198→    }
   199→}
