   202→// AtomicPtr - 원자적 포인터
   203→// ============================================================================
   204→
   205→/// AtomicPtr<T>: 원자적으로 접근 가능한 포인터
   206→pub struct AtomicPtr<T> {
   207→    // 내부 구현: T의 포인터를 원자적으로 저장
   208→    inner: AtomicPtr<T>,
   209→}
   210→
   211→impl<T> AtomicPtr<T> {
   212→    /// 새로운 AtomicPtr을 생성합니다.
   213→    pub fn new(ptr: *mut T) -> AtomicPtr<T> {
   214→        AtomicPtr {
   215→            inner: AtomicPtr::new(ptr),
   216→        }
   217→    }
   218→
   219→    /// 현재 포인터를 읽습니다.
   220→    pub fn load(&self, order: Ordering) -> *mut T {
   221→        let std_order = convert_ordering(order);
   222→        self.inner.load(std_order)
   223→    }
   224→
   225→    /// 포인터를 씁니다.
   226→    pub fn store(&self, ptr: *mut T, order: Ordering) {
   227→        let std_order = convert_ordering(order);
   228→        self.inner.store(ptr, std_order)
   229→    }
   230→
   231→    /// Compare-and-swap: 포인터를 원자적으로 업데이트합니다.
   232→    pub fn compare_and_swap(&self, expected: *mut T, new: *mut T, order: Ordering) -> *mut T {
   233→        let std_order = convert_ordering(order);
   234→        self.inner.compare_and_swap(expected, new, std_order)
   235→    }
   236→}
