   238→// ============================================================================
   239→// Ordering 변환 헬퍼
   240→// ============================================================================
   241→
   242→/// FreeLang의 Ordering을 Rust 표준 라이브러리의 Ordering으로 변환합니다.
   243→fn convert_ordering(order: Ordering) -> StdOrdering {
   244→    match order {
   245→        Ordering::Relaxed => StdOrdering::Relaxed,
   246→        Ordering::Release => StdOrdering::Release,
   247→        Ordering::Acquire => StdOrdering::Acquire,
   248→        Ordering::AcqRel => StdOrdering::AcqRel,
   249→        Ordering::SeqCst => StdOrdering::SeqCst,
   250→    }
   251→}
